const loopData = $input.first().json;

// Get the slot index matching the current time
const timeIndex = loopData.time_index;

// If time_index is null/undefined, default to 0
const safeIndex = timeIndex !== null && timeIndex !== undefined ? timeIndex : 0;

// Extract the correct subfolder for this slot
const subfolderIds = loopData.subfolder_ids || [];
const subfolderNames = loopData.subfolder_names || [];

const currentSubfolderId = subfolderIds[safeIndex] || subfolderIds[0];
const currentSubfolderName = subfolderNames[safeIndex] || subfolderNames[0];

return [{
  json: {
    ...loopData,
    current_subfolder_id: currentSubfolderId,
    current_subfolder_name: currentSubfolderName,
    time_index: safeIndex
  }
}];

// Get all files from Google Drive
const allFiles = $input.all();

// Get config data from the loop
const loopData = $('Loop_Over_Configs').item.json;
const timeIndex = loopData.time_index;
const subfolderIds = loopData.subfolder_ids;
const subfolderNames = loopData.subfolder_names;

// Filter only images and videos
const imageTypes = ['image/jpeg', 'image/png', 'image/gif', 'image/webp', 'image/jpg'];
const videoTypes = ['video/mp4', 'video/quicktime', 'video/x-msvideo', 'video/x-matroska'];

const mediaFiles = allFiles.filter(item => {
  const mimeType = item.json.mimeType;
  return imageTypes.includes(mimeType) || videoTypes.includes(mimeType);
});

if (mediaFiles.length === 0) {
  return [{ 
    json: {
      error: 'No media files found in subfolder',
      config_id: loopData.config_id,
      page_id: loopData.page_id
    }
  }];
}

// Sort by name for stable, predictable ordering
mediaFiles.sort((a, b) => a.json.name.localeCompare(b.json.name));

// Get current index from config
const currentIndex = loopData.current_file_index;

// Wrap around with modulo
const fileIndex = currentIndex % mediaFiles.length;

const selectedFile = mediaFiles[fileIndex].json;

const fileType = imageTypes.includes(selectedFile.mimeType) ? 'image' : 'video';

const nextIndex = currentIndex + 1;

return [{ 
  json: {
    file_id: selectedFile.id,
    file_name: selectedFile.name,
    file_type: fileType,
    mime_type: selectedFile.mimeType,
    current_index: currentIndex,
    next_index: nextIndex,
    total_files: mediaFiles.length,
    config_id: loopData.config_id,
    page_id: loopData.page_id,
    facebook_page_id: loopData.facebook_page_id,
    access_token: loopData.access_token,
    time_index: timeIndex,
    subfolder_id: subfolderIds[timeIndex],
    subfolder_name: subfolderNames[timeIndex]
  }
}];

const fileData = $('Code_Select_File_By_Index').first().json;
const loopData = $('Loop_Over_Configs').first().json;

// Parse captions array
let captions = [];
if (loopData.captions && loopData.captions !== 'null') {
  try {
    captions = Array.isArray(loopData.captions) ? loopData.captions : JSON.parse(loopData.captions);
  } catch(e) {
    captions = [];
  }
}

const timeIndex = fileData.time_index || 0;
const defaultCaption = '📸 Nouveau contenu !';

let caption;
if (captions.length > 0 && captions[timeIndex]) {
  caption = captions[timeIndex];
} else {
  caption = defaultCaption;
}

const inputItem = $input.first();

return [{
  json: {
    file_id: fileData.file_id,
    file_name: fileData.file_name,
    file_type: fileData.file_type,
    mime_type: fileData.mime_type,
    current_index: fileData.current_index,
    next_index: fileData.next_index,
    total_files: fileData.total_files,
    config_id: fileData.config_id,
    page_id: fileData.page_id,
    facebook_page_id: loopData.facebook_page_id,
    access_token: loopData.access_token,
    caption: caption,
    subfolder_id: fileData.subfolder_id,
    subfolder_name: fileData.subfolder_name
  },
  binary: inputItem.binary
}];
